    20→object PdfParser {
    21→
    22→    private val SUMMONS_KEYWORDS = listOf("传票", "开庭", "应诉", "法院", "出庭", "审判")
    23→
    24→    /**
    25→     * 检查文件名是否包含"传票"
    26→     * 用于优先处理明确是传票的文件
    27→     */
    28→    fun isSummonsFile(fileName: String): Boolean {
    29→        return fileName.contains("传票")
    30→    }
    31→
    32→    suspend fun parseAndSync(context: Context, db: AppDatabase, docId: Long) {
    33→        withContext(Dispatchers.IO) {
    34→            val doc = db.documentDao().getById(docId) ?: return@withContext
    35→            val file = File(doc.filePath)
    36→            if (!file.exists()) return@withContext
    37→
    38→            try {
    39→                // 检查文件名是否包含"传票"，如果是则提高解析优先级
    40→                val isNamedSummons = isSummonsFile(doc.fileName) || isSummonsFile(file.name)
    41→
    42→                var text = extractText(file)
    43→                if (text.isBlank()) text = ocrExtract(context, file)
    44→
    45→                // 如果文件名包含"传票"，即使文本解析失败也尝试OCR处理
    46→                val isSummons = isNamedSummons || SUMMONS_KEYWORDS.any { text.contains(it) }
    47→                if (!isSummons) {
    48→                    db.documentDao().update(doc.copy(parseStatus = 3))
    49→                    return@withContext
    50→                }
    51→
    52→                // 标记短信含传票
    53→                val sms = db.smsDao().getById(doc.smsId)
    54→                if (sms != null && !sms.hasSummons) {
    55→                    db.smsDao().update(sms.copy(hasSummons = true))
    56→                }
    57→
    58→                // 对于文件名包含"传票"的文件，使用增强解析
    59→                val info = if (isNamedSummons) {
    60→                    TextParser.parseSummons(text)
    61→                } else {
    62→                    TextParser.parse(text)
    63→                }
    64→
    65→                db.summonsDao().insert(
    66→                    SummonsInfo(
    67→                        documentId = docId, caseNo = info.caseNo, courtName = info.courtName,
    68→                        hearingTime = info.hearingTime, location = info.location,
    69→                        partyName = info.partyName, confidence = if (info.hearingTime > 0) 0.9f else 0.5f
    70→                    )
    71→                )
    72→
    73→                val synced = if (info.hearingTime > 0) {
    74→                    val pdfUri = try {
    75→                        val uri = FileProvider.getUriForFile(context, "${context.packageName}.fileprovider", file)
    76→                        uri.toString()
    77→                    } catch (_: Exception) { doc.filePath }
    78→                    CalendarHelper.syncHearing(context, db, info, docId, "document", pdfFilePath = pdfUri)
    79→                } else false
    80→
    81→                db.documentDao().update(doc.copy(parseStatus = 1, calendarSynced = synced))
    82→            } catch (e: Exception) {
    83→                db.documentDao().update(doc.copy(parseStatus = 2))
    84→            }
    85→        }
    86→    }
    87→
    88→    private fun extractText(file: File): String {
    89→        return try {
    90→            PDDocument.load(file).use { doc ->
    91→                PDFTextStripper().getText(doc).trim()
    92→            }
    93→        } catch (_: Exception) { "" }
    94→    }
    95→
    96→    private suspend fun ocrExtract(context: Context, file: File): String {
    97→        return try {
    98→            val pdDoc = PDDocument.load(file)
    99→            val renderer = PDFRenderer(pdDoc)
   100→            val sb = StringBuilder()
   101→            val pages = minOf(pdDoc.numberOfPages, 3) // OCR first 3 pages max
   102→            for (i in 0 until pages) {
   103→                val bmp = renderer.renderImageWithDPI(i, 200f)
   104→                val text = recognizeText(context, bmp)
   105→                sb.appendLine(text)
   106→                bmp.recycle()
   107→            }
   108→            pdDoc.close()
   109→            sb.toString().trim()
   110→        } catch (_: Exception) { "" }
   111→    }
   112→
   113→    private suspend fun recognizeText(context: Context, bitmap: android.graphics.Bitmap): String {
   114→        return suspendCancellableCoroutine { cont ->
   115→            val recognizer = TextRecognition.getClient(ChineseTextRecognizerOptions.Builder().build())
   116→            val image = InputImage.fromBitmap(bitmap, 0)
   117→            recognizer.process(image)
   118→                .addOnSuccessListener { cont.resume(it.text) }
   119→                .addOnFailureListener { cont.resume("") }
   120→        }
   121→    }
   122→}
