   202→    /** Try download — check content-type for keyword-matched links that may not be PDF */
   203→    private suspend fun tryDownloadPdf(context: Context, db: AppDatabase, smsId: Long, url: String, displayName: String): Boolean {
   204→        if (url.lowercase().let { it.endsWith(".pdf") || it.contains(".pdf?") }) {
   205→            return downloadPdf(context, db, smsId, url, displayName) > 0
   206→        }
   207→        try {
   208→            val request = Request.Builder().url(url).head().build()
   209→            val response = client.newCall(request).execute()
   210→            val contentType = response.header("Content-Type", "") ?: ""
   211→            if (contentType.contains("pdf", ignoreCase = true)) {
   212→                return downloadPdf(context, db, smsId, url, displayName) > 0
   213→            } else {
   214→                Log.d(TAG, "PdfDownloader: skipping non-PDF url=$url contentType=$contentType")
   215→                return false
   216→            }
   217→        } catch (e: Exception) {
   218→            // HEAD failed, try download anyway
   219→            return downloadPdf(context, db, smsId, url, displayName) > 0
   220→        }
   221→    }
